content:
{
  "sentences": [
    {
      "text": "我穿黑色的上衣，你覺得好看嗎？",
      "pinyin": "Wǒ chuān hēisè de shàngyī, nǐ juéde hǎokàn ma?",
      "pinyin_numeric": "wo3 chuan1 hei1 se4 de shang4 yi1, ni3 jue2 de hao3 kan4 ma0",
      "translation_en": "I'm wearing a black top. Do you think it looks good?",
      "translation_ko": "저는 검은색 상의를 입고 있어요. 괜찮아 보이나요?"
    },
    {
      "text": "這件外套的尺寸太大，我想試穿小號的。",
      "pinyin": "Zhè jiàn wàitào de chǐcùn tài dà, wǒ xiǎng shìchuān xiǎohào de.",
      "pinyin_numeric": "zhe4 jian4 wai4 tao4 de chi3 cun4 tai4 da4, wo3 xiang3 shi4 chuan1 xiao3 hao4 de",
      "translation_en": "This jacket's size is too big. I want to try on a small size.",
      "translation_ko": "이 외투 사이즈가 너무 커요. 작은 사이즈를 입어보고 싶어요."
    },
    {
      "text": "你穿藍色的褲子很適合，要不要買？",
      "pinyin": "Nǐ chuān lánsè de kùzi hěn shìhé, yào bù yào mǎi?",
      "pinyin_numeric": "ni3 chuan1 lan2 se4 de ku4 zi5 hen3 shi4 he2, yao4 bu5 yao4 mai3",
      "translation_en": "You look great in blue pants. Do you want to buy them?",
      "translation_ko": "파란색 바지가 잘 어울려요. 사시겠어요?"
    },
    {
      "text": "這件白色的裙子有打折，原價很貴。",
      "pinyin": "Zhè jiàn báisè de qúnzi yǒu dǎzhé, yuánjià hěn guì.",
      "pinyin_numeric": "zhe4 jian4 bai2 se4 de qun2 zi5 you3 da3 zhe2, yuan2 jia4 hen3 gui4",
      "translation_en": "This white skirt is on sale; the original price is very expensive.",
      "translation_ko": "이 흰색 치마는 할인 중이에요. 원래 가격은 매우 비싸요."
    },
    {
      "text": "我穿紅色的上衣，可是尺寸太小了。",
      "pinyin": "Wǒ chuān hóngsè de shàngyī, kěshì chǐcùn tài xiǎo le.",
      "pinyin_numeric": "wo3 chuan1 hong2 se4 de shang4 yi1, ke3 shi4 chi3 cun4 tai4 xiao3 le5",
      "translation_en": "I'm wearing a red top, but the size is too small.",
      "translation_ko": "저는 빨간색 상의를 입고 있는데 사이즈가 너무 작아요."
    },
    {
      "text": "這雙鞋子是黑色的，我想試穿看看。",
      "pinyin": "Zhè shuāng xiézi shì hēisè de, wǒ xiǎng shìchuān kànkan.",
      "pinyin_numeric": "zhe4 shuang1 xie2 zi5 shi4 hei1 se4 de, wo3 xiang3 shi4 chuan1 kan4 kan5",
      "translation_en": "These shoes are black. I want to try them on.",
      "translation_ko": "이 신발은 검은색이에요. 한번 신어보고 싶어요."
    },
    {
      "text": "你穿灰色的褲子，看起來很舒服。",
      "pinyin": "Nǐ chuān huīsè de kùzi, kàn qǐlai hěn shūfu.",
      "pinyin_numeric": "ni3 chuan1 hui1 se4 de ku4 zi5, kan4 qi3 lai5 hen3 shu1 fu5",
      "translation_en": "You're wearing gray pants; they look very comfortable.",
      "translation_ko": "회색 바지를 입으셨네요. 편해 보여요."
    },
    {
      "text": "這件外套的顏色是藍色的，可是我不喜歡。",
      "pinyin": "Zhè jiàn wàitào de yánsè shì lánsè de, kěshì wǒ bù xǐhuān.",
      "pinyin_numeric": "zhe4 jian4 wai4 tao4 de yan2 se4 shi4 lan2 se4 de, ke3 shi4 wo3 bu4 xi3 huan1",
      "translation_en": "This jacket's color is blue, but I don't like it.",
      "translation_ko": "이 외투 색깔은 파란색인데 저는 안 좋아해요."
    },
    {
      "text": "我穿中號的褲子，可是這件太大了。",
      "pinyin": "Wǒ chuān zhōnghào de kùzi, kěshì zhè jiàn tài dà le.",
      "pinyin_numeric": "wo3 chuan1 zhong1 hao4 de ku4 zi5, ke3 shi4 zhe4 jian4 tai4 da4 le5",
      "translation_en": "I wear medium-sized pants, but these are too big.",
      "translation_ko": "저는 중간 사이즈 바지를 입는데 이건 너무 커요."
    },
    {
      "text": "這件白色的上衣很便宜，我想買。",
      "pinyin": "Zhè jiàn báisè de shàngyī hěn piányi, wǒ xiǎng mǎi.",
      "pinyin_numeric": "zhe4 jian4 bai2 se4 de shang4 yi1 hen3 pian2 yi5, wo3 xiang3 mai3",
      "translation_en": "This white top is very cheap. I want to buy it.",
      "translation_ko": "이 흰색 상의는 매우 싸요. 사고 싶어요."
    }
  ]
}
